import { pgTable, text, timestamp, unique, uuid } from "drizzle-orm/pg-core";
import { sql } from "drizzle-orm";

import { companies } from "./companies.ts";

export const waitlistEmails = pgTable(
  "waitlist_emails",
  {
    id: uuid("id")
      .primaryKey()
      .default(sql`gen_random_uuid()`),
    companyId: uuid("company_id")
      .notNull()
      .references(() => companies.id),
    email: text("email").notNull(),
    source: text("source").notNull().default("landing-v1"),
    createdAt: timestamp("created_at", { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (table) => ({
    uniqueCompanyEmail: unique("waitlist_emails_company_email_unique").on(
      table.companyId,
      table.email,
    ),
  }),
);

export type WaitlistEmail = typeof waitlistEmails.$inferSelect;
export type NewWaitlistEmail = typeof waitlistEmails.$inferInsert;

export { companies } from "./companies.ts";
export {
  waitlistEmails,
  type WaitlistEmail,
  type NewWaitlistEmail,
} from "./waitlist-emails.ts";

