import { describe, expect, it } from "vitest";
import { getTableConfig } from "drizzle-orm/pg-core";

import { waitlistEmails } from "./waitlist-emails.ts";

describe("waitlistEmails schema", () => {
  const config = getTableConfig(waitlistEmails);

  it("is named waitlist_emails per the CTO spec", () => {
    expect(config.name).toBe("waitlist_emails");
  });

  it("exposes id, company_id, email, source, created_at columns", () => {
    const names = config.columns.map((c) => c.name).sort();
    expect(names).toEqual([
      "company_id",
      "created_at",
      "email",
      "id",
      "source",
    ]);
  });

  it("defaults source to 'landing-v1'", () => {
    const source = config.columns.find((c) => c.name === "source");
    expect(source?.default).toBe("landing-v1");
  });

  it("declares a unique constraint on (company_id, email)", () => {
    const u = config.uniqueConstraints.find(
      (x) => x.name === "waitlist_emails_company_email_unique",
    );
    expect(u).toBeDefined();
    const cols = u!.columns.map((c) => c.name).sort();
    expect(cols).toEqual(["company_id", "email"]);
  });
});
